# ─── Sound Generation ───────────────────────────────────────────────────────

def generate_tone(freq, duration, volume=0.3, wave_type='sine', sample_rate=SAMPLE_RATE):
    """Generate a numpy audio buffer."""
    frames = int(sample_rate * duration)
    t = np.linspace(0, duration, frames, endpoint=False)
    if wave_type == 'sine':
        wave = np.sin(2 * np.pi * freq * t)
    elif wave_type == 'square':
        wave = np.sign(np.sin(2 * np.pi * freq * t))
    elif wave_type == 'sawtooth':
        wave = 2 * (t * freq - np.floor(t * freq + 0.5))
    elif wave_type == 'noise':
        wave = np.random.uniform(-1, 1, frames)
    else:
        wave = np.sin(2 * np.pi * freq * t)

    # Apply envelope
    envelope = np.ones(frames)
    attack = int(frames * 0.05)
    release = int(frames * 0.2)
    if attack > 0:
        envelope[:attack] = np.linspace(0, 1, attack)
    if release > 0:
        envelope[-release:] = np.linspace(1, 0, release)
    wave = wave * envelope * volume
    return wave.astype(np.float32)


def play_sound_async(wave):
    """Play a sound buffer asynchronously."""

    def _play():
        try:
            sd.play(wave, SAMPLE_RATE)
            sd.wait()
        except Exception:
            pass

    t = Thread(target=_play, daemon=True)
    t.start()


def make_shoot_sound():
    """Player shoot sound."""
    frames = int(SAMPLE_RATE * 0.15)
    t = np.linspace(0, 0.15, frames, endpoint=False)
    freq = np.linspace(800, 200, frames)
    wave = np.sin(2 * np.pi * freq * t)
    envelope = np.linspace(1, 0, frames) ** 2
    return (wave * envelope * 0.4).astype(np.float32)


def make_invader_shoot_sound():
    """Invader shoot sound."""
    frames = int(SAMPLE_RATE * 0.2)
    t = np.linspace(0, 0.2, frames, endpoint=False)
    freq = np.linspace(300, 100, frames)
    wave = np.sign(np.sin(2 * np.pi * freq * t))
    envelope = np.linspace(1, 0, frames) ** 1.5
    return (wave * envelope * 0.3).astype(np.float32)


def make_explosion_sound():
    """Explosion sound."""
    frames = int(SAMPLE_RATE * 0.4)
    noise = np.random.uniform(-1, 1, frames)
    t = np.linspace(0, 0.4, frames, endpoint=False)
    low_freq = np.sin(2 * np.pi * 60 * t)
    wave = noise * 0.7 + low_freq * 0.3
    envelope = np.exp(-t * 8)
    return (wave * envelope * 0.5).astype(np.float32)


def make_invader_death_sound():
    """Invader death sound."""
    frames = int(SAMPLE_RATE * 0.3)
    t = np.linspace(0, 0.3, frames, endpoint=False)
    freq = np.linspace(400, 50, frames)
    noise = np.random.uniform(-1, 1, frames)
    wave = np.sin(2 * np.pi * freq * t) * 0.5 + noise * 0.5
    envelope = np.exp(-t * 6)
    return (wave * envelope * 0.4).astype(np.float32)


def make_march_sound(freq):
    """Invader march sound."""
    frames = int(SAMPLE_RATE * 0.08)
    t = np.linspace(0, 0.08, frames, endpoint=False)
    wave = np.sign(np.sin(2 * np.pi * freq * t))
    envelope = np.ones(frames)
    release = int(frames * 0.3)
    envelope[-release:] = np.linspace(1, 0, release)
    return (wave * envelope * 0.2).astype(np.float32)


def make_ufo_sound_chunk(phase):
    """UFO sound chunk."""
    frames = int(SAMPLE_RATE * 0.05)
    t = np.arange(frames) / SAMPLE_RATE
    freq = 200 + 100 * np.sin(2 * np.pi * 3 * (phase + t))
    wave = np.sin(2 * np.pi * freq * t)
    return (wave * 0.25).astype(np.float32), phase + frames / SAMPLE_RATE


