        angle = i * np.pi / 4 + progress * np.pi
        sx = int(x + np.cos(angle) * radius * 1.2)
        sy = int(y + np.sin(angle) * radius * 1.2)
        pygame.draw.circle(surface, YELLOW, (sx, sy), max(1, 3 - int(progress * 3)))


