# ─── Game Classes ─────────────────────────────────────────────────────────────

class Particle:
    def __init__(self, x, y):
        self.x = x
        self.y = y
        angle = random.uniform(0, 2 * np.pi)
        speed = random.uniform(1, 5)
        self.vx = np.cos(angle) * speed
        self.vy = np.sin(angle) * speed
        self.life = random.randint(20, 40)
        self.max_life = self.life
        self.color = random.choice([YELLOW, ORANGE, RED, WHITE])
        self.size = random.randint(2, 5)

    def update(self):
        self.x += self.vx
        self.y += self.vy
        self.vy += 0.1
        self.life -= 1

    def draw(self, surface):
        alpha = self.life / self.max_life
        r, g, b = self.color
        c = (int(r * alpha), int(g * alpha), int(b * alpha))
        pygame.draw.circle(surface, c, (int(self.x), int(self.y)), self.size)


class Game:
    def __init__(self):
        self.reset()
        self.high_score = 0
        self.stars = [(random.randint(0, WIDTH), random.randint(0, HEIGHT),
                       random.randint(50, 255)) for _ in range(150)]

    def reset(self):
        self.score = 0
        self.lives = 3
        self.level = 1
        self.player_x = WIDTH // 2
        self.player_y = HEIGHT - 60
        self.player_speed = 5
        self.bullets = []
        self.invader_bullets = []
        self.invaders = []
        self.explosions = []
        self.particles = []
        self.shields = []
        self.ufo = None
        self.ufo_timer = 0
        self.ufo_phase = 0.0
        self.ufo_playing = False
        self.march_index = 0
        self.march_timer = 0
        self.march_interval = 60
        self.invader_dir = 1
        self.invader_speed = 1.0
        self.invader_frame = 0
        self.frame_count = 0
        self.game_over = False
        self.game_won = False
        self.shoot_cooldown = 0
        self.invader_shoot_timer = 0
        self.invader_shoot_interval = 90
        self.player_hit_timer = 0
        self.scroll_offset = 0
        self.setup_level()

    def setup_level(self):
        self.invaders = []
        rows = 5
        cols = 11
        start_x = 80
        start_y = 80
        spacing_x = 60
        spacing_y = 50
        for row in range(rows):
            for col in range(cols):
                inv_type = 0 if row == 0 else (1 if row < 3 else 2)
                self.invaders.append({
                    'x': start_x + col * spacing_x,
                    'y': start_y + row * spacing_y,
                    'type': inv_type,
                    'alive': True,
                    'points': [30, 20, 10][inv_type],
                })

        # Shields
        self.shields = []
        for sx in [150, 300, 450, 600]:
            blocks = []
            for brow in range(4):
                for bcol in range(8):
                    bx = sx + bcol * 7
                    by = HEIGHT - 130 + brow * 7
                    blocks.append([bx, by, True])
            self.shields.append({'blocks': blocks})

        self.invader_speed = 1.0 + (self.level - 1) * 0.3
        self.march_interval = max(15, 60 - (self.level - 1) * 8)
        self.invader_shoot_interval = max(30, 90 - (self.level - 1) * 10)

    def get_alive_invaders(self):
        return [inv for inv in self.invaders if inv['alive']]

    def move_invaders(self):
        alive = self.get_alive_invaders()
        if not alive:
            return

        move_down = False
        for inv in alive:
            if inv['x'] > WIDTH - 40 and self.invader_dir > 0:
                move_down = True
                break
            if inv['x'] < 40 and self.invader_dir < 0:
                move_down = True
                break

        if move_down:
            self.invader_dir *= -1
            for inv in alive:
                inv['y'] += 20
        else:
            for inv in alive:
                inv['x'] += self.invader_speed * self.invader_dir

    def invader_shoot(self):
        alive = self.get_alive_invaders()
        if not alive:
            return
        shooter = random.choice(alive)
        self.invader_bullets.append({
            'x': shooter['x'],
            'y': shooter['y'] + 15,
            'speed': 4 + self.level * 0.5,
        })
        play_sound_async(INVADER_SHOOT_SOUND)

    def check_bullet_shield(self, bx, by, is_player_bullet):
        for shield in self.shields:
            for block in shield['blocks']:
                if block[2]:
                    if abs(bx - block[0]) < 8 and abs(by - block[1]) < 8:
                        block[2] = False
                        return True
        return False

    def update(self):
        if self.game_over or self.game_won:
            return

        self.frame_count += 1
        self.scroll_offset = (self.scroll_offset + 0.2) % HEIGHT

        # Player movement
        keys = pygame.key.get_pressed()
        if keys[pygame.K_LEFT] or keys[pygame.K_a]:
            self.player_x = max(20, self.player_x - self.player_speed)
        if keys[pygame.K_RIGHT] or keys[pygame.K_d]:
            self.player_x = min(WIDTH - 20, self.player_x + self.player_speed)

        # Shooting
        if self.shoot_cooldown > 0:
            self.shoot_cooldown -= 1
        if (keys[pygame.K_SPACE] or keys[pygame.K_UP]) and self.shoot_cooldown == 0:
            self.bullets.append({'x': self.player_x, 'y': self.player_y - 20, 'speed': 10})
            play_sound_async(SHOOT_SOUND)
            self.shoot_cooldown = 20

        # Move player bullets
        for b in self.bullets[:]:
            b['y'] -= b['speed']
            if b['y'] < 0:
                self.bullets.remove(b)

        # Move invader bullets
        for b in self.invader_bullets[:]:
            b['y'] += b['speed']
            if b['y'] > HEIGHT:
                self.invader_bullets.remove(b)

        # March invaders
        self.march_timer += 1
        if self.march_timer >= self.march_interval:
            self.march_timer = 0
            self.move_invaders()
            self.invader_frame = (self.invader_frame + 1) % 2
            play_sound_async(MARCH_SOUNDS[self.march_index % 4])
            self.march_index += 1

        # Invader shooting
        self.invader_shoot_timer += 1
        if self.invader_shoot_timer >= self.invader_shoot_interval:
            self.invader_shoot_timer = 0
            self.invader_shoot()

        # UFO
        self.ufo_timer += 1
        if self.ufo_timer > 600 and self.ufo is None:
            self.ufo = {'x': -30, 'y': 40, 'speed': 2, 'points': random.choice([50, 100, 150, 300])}
            self.ufo_timer = 0

        if self.ufo:
            self.ufo['x'] += self.ufo['speed']
            if self.ufo['x'] > WIDTH + 30:
                self.ufo = None

        # Check player bullet hits
        for b in self.bullets[:]:
            # Hit invader
            for inv in self.invaders:
                if inv['alive']:
                    if abs(b['x'] - inv['x']) < 18 and abs(b['y'] - inv['y']) < 18:
                        inv['alive'] = False
                        self.score += inv['points']
                        self.bullets.remove(b)
                        self.explosions.append({'x': inv['x'], 'y': inv['y'], 'frame': 0, 'max': 20})
                        for _ in range(15):
                            self.particles.append(Particle(inv['x'], inv['y']))
                        play_sound_async(INVADER_DEATH_SOUND)
                        break
            else:
                # Hit UFO
                if self.ufo and b in self.bullets:
                    if abs(b['x'] - self.ufo['x']) < 25 and abs(b['y'] - self.ufo['y']) < 15:
                        self.score += self.ufo['points']
                        self.explosions.append({'x': self.ufo['x'], 'y': self.ufo['y'], 'frame': 0, 'max': 25})
                        for _ in range(20):
                            self.particles.append(Particle(self.ufo['x'], self.ufo['y']))
                        self.ufo = None
                        if b in self.bullets:
                            self.bullets.remove(b)
                        play_sound_async(EXPLOSION_SOUND)
                        continue

                # Hit shield
                if b in self.bullets:
                    if self.check_bullet_shield(b['x'], b['y'], True):
                        self.bullets.remove(b)

        # Check invader bullet hits
        for b in self.invader_bullets[:]:
            # Hit player
            if abs(b['x'] - self.player_x) < 18 and abs(b['y'] - self.player_y) < 20:
                self.invader_bullets.remove(b)
                self.lives -= 1
                self.player_hit_timer = 60
                self.explosions.append({'x': self.player_x, 'y': self.player_y, 'frame': 0, 'max': 30})
                for _ in range(25):
                    self.particles.append(Particle(self.player_x, self.player_y))
                play_sound_async(EXPLOSION_SOUND)
                if self.lives <= 0:
                    self.game_over = True
                    play_sound_async(GAME_OVER_SOUND)
                continue

            # Hit shield
            if self.check_bullet_shield(b['x'], b['y'], False):
                self.invader_bullets.remove(b)

        # Check invaders reached bottom
        for inv in self.get_alive_invaders():
            if inv['y'] > HEIGHT - 80:
                self.game_over = True
                play_sound_async(GAME_OVER_SOUND)

        # Update explosions
        for exp in self.explosions[:]:
            exp['frame'] += 1
            if exp['frame'] >= exp['max']:
                self.explosions.remove(exp)

        # Update particles
        for p in self.particles[:]:
            p.update()
            if p.life <= 0:
                self.particles.remove(p)

        # Check win
        if not self.get_alive_invaders():
            self.level += 1
            play_sound_async(LEVEL_UP_SOUND)
            self.bullets.clear()
            self.invader_bullets.clear()
            self.explosions.clear()
            self.particles.clear()
            self.ufo = None
            self.setup_level()

        # Update high score
        if self.score > self.high_score:
            self.high_score = self.score

    def draw(self, surface):
        surface.fill(BLACK)

        # Stars
        draw_star_field(surface, self.stars)

        # Nebula effect (subtle)
        for i in range(3):
            nx = (100 + i * 250) % WIDTH
            ny = (200 + i * 100) % HEIGHT
            for r in range(40, 0, -10):
                alpha_surf = pygame.Surface((r * 2, r * 2), pygame.SRCALPHA)
                col = [(30, 0, 60), (0, 20, 60), (0, 40, 20)][i]
                pygame.draw.circle(alpha_surf, (*col, 15), (r, r), r)
                surface.blit(alpha_surf, (nx - r, ny - r))

        # Shields
        for shield in self.shields:
            draw_shield(surface, shield)

        # Invaders
        for inv in self.invaders:
            if inv['alive']:
                draw_invader(surface, inv['x'], inv['y'], inv['type'], self.invader_frame)

        # UFO
        if self.ufo:
            draw_ufo(surface, self.ufo['x'], self.ufo['y'])
            # UFO score hint
            font_small = pygame.font.SysFont('monospace', 12)
            txt = font_small.render(f"?", True, YELLOW)
            surface.blit(txt, (self.ufo['x'] - 4, self.ufo['y'] - 25))

        # Player bullets
        for b in self.bullets:
            draw_bullet(surface, b['x'], b['y'])

        # Invader bullets
        for b in self.invader_bullets:
            draw_invader_bullet(surface, b['x'], b['y'])

        # Player
        if self.player_hit_timer > 0:
            self.player_hit_timer -= 1
            if self.player_hit_timer % 6 < 3:
                draw_player(surface, self.player_x, self.player_y)
        else:
            draw_player(surface, self.player_x, self.player_y)

        # Explosions
        for exp in self.explosions:
            draw_explosion(surface, exp['x'], exp['y'], exp['frame'], exp['max'])

        # Particles
        for p in self.particles:
            p.draw(surface)

        # HUD
        self.draw_hud(surface)

        # Game over / win screen
        if self.game_over:
            self.draw_overlay(surface, "GAME OVER", RED)
        elif self.game_won:
            self.draw_overlay(surface, "YOU WIN!", GREEN)

    def draw_hud(self, surface):
        font = pygame.font.SysFont('monospace', 20, bold=True)
        font_small = pygame.font.SysFont('monospace', 16)

        # Score
        score_txt = font.render(f"SCORE: {self.score:06d}", True, WHITE)
        surface.blit(score_txt, (10, 10))

        # High score
        hi_txt = font_small.render(f"HI: {self.high_score:06d}", True, YELLOW)
        surface.blit(hi_txt, (WIDTH // 2 - 60, 10))

        # Level
        lvl_txt = font.render(f"LEVEL: {self.level}", True, CYAN)
        surface.blit(lvl_txt, (WIDTH - 140, 10))

        # Lives
        lives_txt = font_small.render("LIVES:", True, WHITE)
        surface.blit(lives_txt, (10, HEIGHT - 35))
        for i in range(self.lives):
            draw_player(surface, 90 + i * 35, HEIGHT - 22)

        # Bottom line
        pygame.draw.line(surface, GREEN, (0, HEIGHT - 50), (WIDTH, HEIGHT - 50), 2)
        pygame.draw.line(surface, GREEN, (0, 35), (WIDTH, 35), 1)

    def draw_overlay(self, surface, text, color):
        overlay = pygame.Surface((WIDTH, HEIGHT), pygame.SRCALPHA)
        overlay.fill((0, 0, 0, 120))
        surface.blit(overlay, (0, 0))

        font_big = pygame.font.SysFont('monospace', 64, bold=True)
        font_med = pygame.font.SysFont('monospace', 28)
        font_small = pygame.font.SysFont('monospace', 20)

        txt = font_big.render(text, True, color)
        surface.blit(txt, (WIDTH // 2 - txt.get_width() // 2, HEIGHT // 2 - 80))

        score_txt = font_med.render(f"FINAL SCORE: {self.score}", True, YELLOW)
        surface.blit(score_txt, (WIDTH // 2 - score_txt.get_width() // 2, HEIGHT // 2))

        restart_txt = font_small.render("Press R to Restart or Q to Quit", True, WHITE)
        surface.blit(restart_txt, (WIDTH // 2 - restart_txt.get_width() // 2, HEIGHT // 2 + 60))


# ─── Main ─────────────────────────────────────────────────────────────────────

def draw_title_screen(surface, stars):
    surface.fill(BLACK)
    draw_star_field(surface, stars)

    font_title = pygame.font.SysFont('monospace', 72, bold=True)
    font_sub = pygame.font.SysFont('monospace', 24)
    font_small = pygame.font.SysFont('monospace', 18)

    # Animated title
    t = time.time()
    r = int(127 + 127 * np.sin(t * 2))
    g = int(127 + 127 * np.sin(t * 2 + 2))
    b = int(127 + 127 * np.sin(t * 2 + 4))

    title = font_title.render("SPACE", True, (r, g, b))
    title2 = font_title.render("INVADERS", True, (b, r, g))
    surface.blit(title, (WIDTH // 2 - title.get_width() // 2, 100))
    surface.blit(title2, (WIDTH // 2 - title2.get_width() // 2, 170))

    # Score legend
    legend_items = [
        ("= 30 pts", MAGENTA, 0),
        ("= 20 pts", GREEN, 1),
        ("= 10 pts", YELLOW, 2),
        ("= ??? pts", RED, -1),
    ]

    for i, (label, color, inv_type) in enumerate(legend_items):
        y = 290 + i * 45
        if inv_type >= 0:
            draw_invader(surface, WIDTH // 2 - 80, y, inv_type, int(t * 2) % 2)
        else:
            draw_ufo(surface, WIDTH // 2 - 80, y)
        txt = font_sub.render(label, True, color)
        surface.blit(txt, (WIDTH // 2 - 50, y - 10))

    start_txt = font_small.render("Press SPACE or ENTER to Start", True, WHITE if int(t * 2) % 2 == 0 else CYAN)
    surface.blit(start_txt, (WIDTH // 2 - start_txt.get_width() // 2, 510))

    controls = font_small.render("Arrow Keys / WASD to Move | SPACE to Shoot", True, (150, 150, 150))
    surface.blit(controls, (WIDTH // 2 - controls.get_width() // 2, 545))


def main():
    print("Starting Space Invaders...")
    print("Controls: Arrow Keys or WASD to move, SPACE to shoot")
    print("Press R to restart, Q to quit")

    stars = [(random.randint(0, WIDTH), random.randint(0, HEIGHT),
              random.randint(50, 255)) for _ in range(150)]

    game = Game()
    title_screen = True

    running = True
    while running:
        for event in pygame.event.get():
            if event.type == pygame.QUIT:
                running = False
            if event.type == pygame.KEYDOWN:
                if event.key in (pygame.K_q, pygame.K_ESCAPE):
                    running = False
                if title_screen:
                    if event.key in (pygame.K_SPACE, pygame.K_RETURN):
                        title_screen = False
                        print("Game started!")
                else:
                    if event.key == pygame.K_r:
                        game.reset()
                        print(f"Game restarted! High score: {game.high_score}")

        if title_screen:
            draw_title_screen(screen, stars)
        else:
            game.update()
            game.draw(screen)

        pygame.display.flip()
        clock.tick(FPS)

    pygame.quit()
    print("Thanks for playing Space Invaders!")
    print(f"Final High Score: {game.high_score}")
    sys.exit()


if __name__ == "__main__":
    main()